from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api', methods=['GET'])
def api():
    auth_header = request.headers.get('Authorization')
    
    if not auth_header:
        return jsonify({'error': 'Missing Authorization header'}), 401
    
    token_parts = auth_header.split()
    
    if len(token_parts) != 2 or token_parts[0] != 'Bearer':
        return jsonify({'error': 'Invalid Authorization header format'}), 401
    
    token = token_parts[1]
    
    try:
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        user_claims = decoded_token
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401
    
    # Forward user claims to backend services
    backend_response = forward_to_backend(user_claims)
    
    return backend_response

def forward_to_backend(user_claims):
    # Simulate forwarding to a backend service
    return jsonify({'message': 'Request processed', 'user_claims': user_claims})

if __name__ == '__main__':
    app.run(debug=True)